class Solution {
public:
    vector<int> findSubstring(string s, vector<string>& words) {
        if (s.empty() || words.empty()) return {};

        int wordCount = words.size();
        int wordLength = words[0].size();
        int totalLength = wordCount * wordLength;
        unordered_map<string, int> wordCountMap;

        for (const auto& word : words) {
            ++wordCountMap[word];
        }

        vector<int> result;
        for (int i = 0; i <= s.size() - totalLength; ++i) {
            unordered_map<string, int> tempMap = wordCountMap;
            for (int j = 0; j < wordCount; ++j) {
                int index = i + j * wordLength;
                string substr = s.substr(index, wordLength);
                if (tempMap.find(substr) == tempMap.end() || --tempMap[substr] < 0) {
                    break;
                }
                if (j == wordCount - 1) {
                    result.push_back(i);
                }
            }
        }
        return result;
    }
};
